/**
 * Create the Client
 */
const config = {
  "previewFeatures": [
    "driverAdapters",
    "fullTextSearchPostgres"
  ],
  "clientVersion": "7.1.0",
  "engineVersion": "ab635e6b9d606fa5c8fb8b1a7f909c3c3c1c98ba",
  "activeProvider": "postgresql",
  "inlineSchema": "generator client {\n  provider        = \"prisma-client-js\"\n  output          = \"./generated/prisma\"\n  previewFeatures = [\"driverAdapters\", \"fullTextSearchPostgres\"]\n}\n\ndatasource db {\n  provider = \"postgresql\"\n}\n\n// =============================================================================\n// USER MANAGEMENT\n// =============================================================================\n\nmodel User {\n  id             String     @id @default(uuid())\n  email          String     @unique\n  username       String?    @unique\n  name           String?\n  createdAt      DateTime   @default(now())\n  updatedAt      DateTime   @updatedAt\n  hashedPassword String?\n  role           UserRole   @default(USER)\n  roles          UserRole[] @default([USER])\n  isActive       Boolean    @default(true)\n  lastLogin      DateTime?\n  preferences    Json?\n  refreshToken   String?\n  deletedAt      DateTime?\n\n  // OAuth fields\n  googleId      String?   @unique\n  githubId      String?   @unique\n  picture       String?\n  emailVerified DateTime?\n\n  // Relationships\n  agents               Agent[]\n  pipelines            Pipeline[]\n  tasks                Task[]\n  workflows            Workflow[]\n  chatRooms            ChatRoom[]\n  messages             Message[]\n  authSessions         AuthSession[]\n  loginAttempts        LoginAttempt[]\n  authEvents           AuthEvent[]\n  chatRoomParticipants ChatRoomParticipant[]\n  readReceipts         ReadReceipt[]\n  messageReactions     MessageReaction[]\n\n  // Performance indexes\n  @@index([email, isActive])\n  @@index([role, isActive])\n  @@index([lastLogin])\n  @@index([createdAt])\n  @@map(\"users\")\n}\n\nenum UserRole {\n  USER\n  ADMIN\n  SUPER_ADMIN\n  AGENCY_OWNER\n  AGENCY_ADMIN\n  AGENCY_MANAGER\n  AGENT_OPERATOR\n}\n\n// =============================================================================\n// AUTHENTICATION\n// =============================================================================\n\nmodel AuthSession {\n  id        String   @id @default(uuid())\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  userId    String\n  token     String   @unique\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n\n  @@map(\"auth_sessions\")\n}\n\nmodel LoginAttempt {\n  id         String   @id @default(uuid())\n  user       User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  userId     String\n  ipAddress  String\n  successful Boolean\n  createdAt  DateTime @default(now())\n\n  @@map(\"login_attempts\")\n}\n\nmodel AuthEvent {\n  id        String   @id @default(uuid())\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  userId    String\n  type      String\n  details   Json?\n  createdAt DateTime @default(now())\n\n  @@map(\"auth_events\")\n}\n\n// =============================================================================\n// AGENT SYSTEM\n// =============================================================================\n\nmodel Agent {\n  id           String            @id @default(uuid())\n  name         String\n  type         AgentType\n  status       AgentStatus       @default(INACTIVE)\n  description  String?\n  systemPrompt String?\n  config       Json?\n  capabilities AgentCapability[] @default([])\n  provider     String            @default(\"default\")\n  userId       String\n  createdAt    DateTime          @default(now())\n  updatedAt    DateTime          @updatedAt\n  deletedAt    DateTime?\n\n  // Relationships\n  user           User                 @relation(fields: [userId], references: [id], onDelete: Cascade)\n  metadata       AgentMetadata?\n  nft            AgentNFT?\n  wallet         Wallet?\n  chats          Chat[]\n  messages       Message[]\n  codeExecutions CodeExecutionUsage[]\n  pipelines      Pipeline[]\n  tasks          Task[]\n  workflows      Workflow[]\n  workflowSteps  WorkflowStep[]\n  registration   AgentRegistration?\n\n  // Performance indexes\n  @@index([userId, status, type])\n  @@index([status, updatedAt])\n  @@index([type, createdAt])\n  @@index([userId, deletedAt])\n  @@map(\"agents\")\n}\n\nmodel AgentMetadata {\n  id       String @id @default(uuid())\n  agentId  String @unique\n  metadata Json   @default(\"{}\")\n\n  // Relationships\n  agent Agent @relation(fields: [agentId], references: [id], onDelete: Cascade)\n\n  @@map(\"agent_metadata\")\n}\n\nenum AgentType {\n  BASIC\n  CHAT\n  WORKFLOW\n  TASK\n  ASSISTANT\n  ANALYSIS\n  CONVERSATIONAL\n  IDE_EXTENSION\n  API\n}\n\nenum AgentStatus {\n  ACTIVE\n  INACTIVE\n  IDLE\n  BUSY\n  ERROR\n  OFFLINE\n  INITIALIZING\n  READY\n  TERMINATED\n}\n\nenum AgentCapability {\n  CODE_GENERATION\n  CODE_REVIEW\n  CODE_REFACTORING\n  CODE_EXECUTION\n  DEBUGGING\n  TESTING\n  DOCUMENTATION\n  ARCHITECTURE_DESIGN\n  OPTIMIZATION\n  SECURITY_AUDIT\n  PROJECT_MANAGEMENT\n  TOOL_USAGE\n  TASK_EXECUTION\n  FILE_MANAGEMENT\n  CODE_COMPLETION\n  CODE_SUGGESTIONS\n  SYNTAX_HIGHLIGHTING\n  ERROR_DETECTION\n  CODE_FORMATTING\n  INTELLISENSE\n  CHAT\n  WORKFLOW\n  RESEARCH\n  ANALYSIS\n  INTEGRATION\n}\n\n// =============================================================================\n// CHAT SYSTEM\n// =============================================================================\n\nmodel Chat {\n  id        String    @id @default(uuid())\n  title     String?\n  agentId   String\n  userId    String?\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n  deletedAt DateTime?\n\n  // Relationships\n  agent    Agent     @relation(fields: [agentId], references: [id], onDelete: Cascade)\n  messages Message[]\n\n  @@map(\"chats\")\n}\n\nmodel ChatRoom {\n  id              String       @id @default(uuid())\n  name            String\n  description     String?\n  topic           String? // Current discussion topic\n  purpose         String? // Room purpose/goal\n  type            ChatRoomType @default(PUBLIC)\n  isPrivate       Boolean      @default(false)\n  isEphemeral     Boolean      @default(false) // Auto-delete after inactivity\n  owner           User         @relation(fields: [ownerId], references: [id])\n  ownerId         String\n  settings        Json? // Room settings (auto-summarize, etc.)\n  metadata        Json? // Custom metadata\n  createdAt       DateTime     @default(now())\n  updatedAt       DateTime     @updatedAt\n  lastMessageAt   DateTime?\n  isActive        Boolean      @default(true)\n  expiresAt       DateTime? // For ephemeral rooms\n  deletedAt       DateTime?\n  maxParticipants Int          @default(50)\n\n  // Relationships\n  messages     Message[]\n  participants ChatRoomParticipant[]\n  readReceipts ReadReceipt[]\n\n  // Performance indexes\n  @@index([ownerId, isActive])\n  @@index([type, isActive])\n  @@index([lastMessageAt])\n  @@index([isActive, expiresAt])\n  @@map(\"chat_rooms\")\n}\n\nenum ChatRoomType {\n  PUBLIC // Open to all\n  PRIVATE // Invite-only\n  PERSISTENT // Long-term project rooms\n  EPHEMERAL // Auto-delete after completion\n  AGENT_ONLY // Only agents can participate\n  MIXED // Agents and humans\n}\n\nmodel ChatRoomParticipant {\n  id            String                  @id @default(uuid())\n  room          ChatRoom                @relation(fields: [roomId], references: [id], onDelete: Cascade)\n  roomId        String\n  user          User?                   @relation(fields: [userId], references: [id])\n  userId        String?\n  agentId       String? // For agent participants\n  role          ChatRoomParticipantRole @default(PARTICIPANT)\n  permissions   String[]                @default([])\n  isTyping      Boolean                 @default(false)\n  lastTypingAt  DateTime?\n  lastReadAt    DateTime?\n  joinedAt      DateTime                @default(now())\n  leftAt        DateTime?\n  isMuted       Boolean                 @default(false)\n  notifications Boolean                 @default(true)\n\n  @@unique([roomId, userId])\n  @@unique([roomId, agentId])\n  @@map(\"chat_room_participants\")\n}\n\nenum ChatRoomParticipantRole {\n  ADMIN // Full control\n  MODERATOR // Can moderate messages\n  PARTICIPANT // Regular participant\n  OBSERVER // Read-only access\n}\n\nmodel ReadReceipt {\n  id        String   @id @default(uuid())\n  message   Message  @relation(fields: [messageId], references: [id], onDelete: Cascade)\n  messageId String\n  room      ChatRoom @relation(fields: [roomId], references: [id], onDelete: Cascade)\n  roomId    String\n  user      User?    @relation(fields: [userId], references: [id])\n  userId    String?\n  agentId   String? // For agent read receipts\n  readAt    DateTime @default(now())\n\n  @@unique([messageId, userId])\n  @@unique([messageId, agentId])\n  @@map(\"read_receipts\")\n}\n\nmodel MessageReaction {\n  id        String   @id @default(uuid())\n  message   Message  @relation(fields: [messageId], references: [id], onDelete: Cascade)\n  messageId String\n  user      User?    @relation(fields: [userId], references: [id])\n  userId    String?\n  agentId   String? // For agent reactions\n  emoji     String // Emoji or reaction type\n  createdAt DateTime @default(now())\n\n  @@unique([messageId, userId, emoji])\n  @@unique([messageId, agentId, emoji])\n  @@map(\"message_reactions\")\n}\n\nmodel Message {\n  id              String      @id @default(uuid())\n  content         String      @db.Text\n  type            MessageType @default(TEXT)\n  role            MessageRole @default(USER)\n  sender          User?       @relation(fields: [senderId], references: [id])\n  senderId        String?\n  senderName      String? // For DTO compatibility - plain string sender\n  agent           Agent?      @relation(fields: [agentId], references: [id])\n  agentId         String?\n  chat            Chat?       @relation(fields: [chatId], references: [id])\n  chatId          String?\n  room            ChatRoom?   @relation(fields: [roomId], references: [id])\n  roomId          String?\n  parentMessage   Message?    @relation(\"MessageReplies\", fields: [parentMessageId], references: [id])\n  parentMessageId String?\n  replies         Message[]   @relation(\"MessageReplies\")\n  metadata        Json?\n  attachments     String[]    @default([])\n  codeSnippet     Json? // {language, code, syntax}\n  taskAssignment  Json? // {assignedTo, dueDate, priority}\n  workflowTrigger Json? // {workflowId, action, params}\n  timestamp       DateTime    @default(now())\n  updatedAt       DateTime    @updatedAt\n  isEdited        Boolean     @default(false)\n  isDeleted       Boolean     @default(false)\n  isPinned        Boolean     @default(false)\n\n  // Relationships\n  readReceipts     ReadReceipt[]\n  messageReactions MessageReaction[]\n\n  // Performance indexes\n  @@index([roomId, timestamp])\n  @@index([senderId, timestamp])\n  @@index([agentId, timestamp])\n  @@index([chatId, timestamp])\n  @@index([roomId, isDeleted, timestamp])\n  @@map(\"messages\")\n}\n\nenum MessageType {\n  TEXT // Regular text message\n  CODE // Code snippet\n  FILE // File attachment\n  TASK // Task assignment\n  WORKFLOW // Workflow trigger\n  SYSTEM // System notification\n  SUMMARY // AI-generated summary\n  SUGGESTION // Agent suggestion\n}\n\nenum MessageRole {\n  USER\n  AGENT\n  SYSTEM\n  ASSISTANT\n  TOOL\n}\n\n// =============================================================================\n// WORKFLOW SYSTEM\n// =============================================================================\n\nmodel Workflow {\n  id             String         @id @default(uuid())\n  name           String\n  description    String?\n  definition     Json? // Workflow definition JSON\n  status         WorkflowStatus @default(DRAFT)\n  creator        User?          @relation(fields: [creatorId], references: [id])\n  creatorId      String?\n  agent          Agent?         @relation(fields: [agentId], references: [id])\n  agentId        String?\n  metadata       Json?\n  isActive       Boolean        @default(true)\n  variables      Json?\n  triggers       Json?          @db.Json\n  createdAt      DateTime       @default(now())\n  updatedAt      DateTime       @updatedAt\n  lastExecutedAt DateTime?\n  executionCount Int            @default(0)\n  statistics     Json?\n  deletedAt      DateTime?\n\n  // Relationships\n  steps      WorkflowStep[]\n  executions WorkflowExecution[]\n\n  // Performance indexes\n  @@index([creatorId, status, updatedAt])\n  @@index([agentId, isActive])\n  @@index([status, lastExecutedAt])\n  @@index([isActive, createdAt])\n  @@map(\"workflows\")\n}\n\nmodel WorkflowStep {\n  id              String    @id @default(uuid())\n  name            String\n  type            String\n  config          Json?\n  order           Int       @default(0)\n  workflow        Workflow? @relation(fields: [workflowId], references: [id])\n  workflowId      String?\n  agent           Agent?    @relation(fields: [agentId], references: [id])\n  agentId         String?\n  nextSteps       String[]\n  conditions      Json?\n  transformations Json?\n  metadata        Json?\n  isActive        Boolean   @default(true)\n  createdAt       DateTime  @default(now())\n  updatedAt       DateTime  @updatedAt\n  lastExecutedAt  DateTime?\n  statistics      Json?\n\n  @@map(\"workflow_steps\")\n}\n\nmodel WorkflowExecution {\n  id          String                  @id @default(uuid())\n  workflow    Workflow                @relation(fields: [workflowId], references: [id])\n  workflowId  String\n  status      WorkflowExecutionStatus @default(PENDING)\n  input       Json?\n  output      Json?\n  error       String?\n  startedAt   DateTime                @default(now())\n  completedAt DateTime?\n\n  @@map(\"workflow_executions\")\n}\n\nenum WorkflowStatus {\n  DRAFT\n  PUBLISHED\n  ARCHIVED\n  ACTIVE\n  PAUSED\n  COMPLETED\n  FAILED\n}\n\nenum WorkflowExecutionStatus {\n  PENDING\n  RUNNING\n  COMPLETED\n  FAILED\n  CANCELLED\n}\n\n// =============================================================================\n// PIPELINE SYSTEM\n// =============================================================================\n\nmodel Pipeline {\n  id            String         @id @default(uuid())\n  name          String\n  description   String?\n  configuration Json?\n  status        PipelineStatus @default(DRAFT)\n  user          User           @relation(fields: [userId], references: [id], onDelete: Cascade)\n  userId        String\n  agent         Agent          @relation(fields: [agentId], references: [id])\n  agentId       String\n  createdAt     DateTime       @default(now())\n  updatedAt     DateTime       @updatedAt\n  deletedAt     DateTime?\n\n  // Relationships\n  tasks Task[]\n\n  @@map(\"pipelines\")\n}\n\nenum PipelineStatus {\n  DRAFT\n  ACTIVE\n  PAUSED\n  COMPLETED\n  FAILED\n}\n\n// =============================================================================\n// TASK SYSTEM\n// =============================================================================\n\nmodel Task {\n  id         String       @id @default(uuid())\n  type       String\n  status     TaskStatus   @default(PENDING)\n  priority   TaskPriority @default(MEDIUM)\n  data       Json?\n  result     Json?\n  error      String?\n  startTime  DateTime?\n  endTime    DateTime?\n  pipeline   Pipeline     @relation(fields: [pipelineId], references: [id])\n  pipelineId String\n  agent      Agent?       @relation(fields: [agentId], references: [id])\n  agentId    String?\n  user       User         @relation(fields: [userId], references: [id])\n  userId     String\n  createdAt  DateTime     @default(now())\n  updatedAt  DateTime     @updatedAt\n  deletedAt  DateTime?\n\n  // Relationships\n  taskExecutions TaskExecution[]\n\n  @@map(\"tasks\")\n}\n\nmodel TaskExecution {\n  id          String    @id @default(uuid())\n  task        Task      @relation(fields: [taskId], references: [id], onDelete: Cascade)\n  taskId      String\n  status      String\n  output      Json?\n  error       String?\n  startedAt   DateTime  @default(now())\n  completedAt DateTime?\n\n  @@map(\"task_executions\")\n}\n\nenum TaskStatus {\n  PENDING\n  IN_PROGRESS\n  COMPLETED\n  FAILED\n  CANCELLED\n}\n\nenum TaskPriority {\n  LOW\n  MEDIUM\n  HIGH\n  URGENT\n}\n\n// =============================================================================\n// CODE EXECUTION SYSTEM\n// =============================================================================\n\nmodel CodeExecutionUsage {\n  id            String                @id @default(uuid())\n  agentId       String\n  clientId      String\n  executionId   String                @unique\n  language      CodeExecutionLanguage\n  code          String                @db.Text\n  result        Json?\n  output        Json?\n  error         Json?\n  executionTime Int // in milliseconds\n  memoryUsage   Int // in bytes\n  computeUnits  Float\n  cost          Float\n  tier          CodeExecutionTier\n  environment   String\n  status        CodeExecutionStatus\n  createdAt     DateTime              @default(now())\n  completedAt   DateTime?\n\n  // Relationships\n  agent Agent @relation(fields: [agentId], references: [id])\n\n  @@index([agentId])\n  @@index([clientId])\n  @@index([createdAt])\n  @@index([language])\n  @@index([tier])\n  @@index([status])\n  @@map(\"code_execution_usage\")\n}\n\nmodel CodeExecutionSession {\n  id            String    @id @default(uuid())\n  name          String\n  description   String?\n  ownerId       String\n  collaborators String[]\n  isPublic      Boolean   @default(false)\n  files         Json // Array of file objects\n  environment   Json // Environment configuration\n  createdAt     DateTime  @default(now())\n  updatedAt     DateTime  @updatedAt\n  expiresAt     DateTime?\n  storageUsage  Int       @default(0) // in bytes\n\n  @@map(\"code_execution_sessions\")\n}\n\nenum CodeExecutionLanguage {\n  JAVASCRIPT\n  TYPESCRIPT\n  PYTHON\n  RUBY\n  SHELL\n  HTML\n  CSS\n}\n\nenum CodeExecutionTier {\n  BASIC\n  STANDARD\n  PREMIUM\n  ENTERPRISE\n}\n\nenum CodeExecutionStatus {\n  PENDING\n  RUNNING\n  COMPLETED\n  FAILED\n  TIMEOUT\n  CANCELLED\n}\n\n// =============================================================================\n// NFT AND MARKETPLACE MODELS\n// =============================================================================\n\nmodel AgentNFT {\n  id                  String   @id @default(uuid())\n  agentId             String   @unique\n  tokenId             Int      @unique\n  contractAddress     String\n  smartAccountAddress String?\n  isFractionalized    Boolean  @default(false)\n  totalShares         Int      @default(0)\n  metadataUri         String?\n  createdAt           DateTime @default(now())\n  updatedAt           DateTime @updatedAt\n\n  agent               Agent?               @relation(fields: [agentId], references: [id])\n  fractionalShares    FractionalShare[]\n  revenueStreams      RevenueStream[]\n  marketplaceListings MarketplaceListing[]\n\n  @@map(\"agent_nfts\")\n}\n\nmodel FractionalShare {\n  id           String   @id @default(uuid())\n  agentNFTId   String\n  ownerAddress String\n  shareAmount  Decimal\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  agentNFT AgentNFT @relation(fields: [agentNFTId], references: [id], onDelete: Cascade)\n\n  @@map(\"fractional_shares\")\n}\n\nmodel RevenueStream {\n  id                    String   @id @default(uuid())\n  agentNFTId            String\n  streamName            String\n  description           String?\n  tokenAddress          String\n  totalRevenue          Decimal\n  distributedRevenue    Decimal\n  distributionThreshold Decimal\n  isActive              Boolean  @default(true)\n  createdAt             DateTime @default(now())\n  updatedAt             DateTime @updatedAt\n\n  agentNFT      AgentNFT              @relation(fields: [agentNFTId], references: [id], onDelete: Cascade)\n  distributions RevenueDistribution[]\n\n  @@map(\"revenue_streams\")\n}\n\nmodel RevenueDistribution {\n  id              String   @id @default(uuid())\n  revenueStreamId String\n  txHash          String\n  totalAmount     Decimal\n  distributedTo   Json\n  blockNumber     Int\n  createdAt       DateTime @default(now())\n\n  revenueStream RevenueStream @relation(fields: [revenueStreamId], references: [id], onDelete: Cascade)\n\n  @@map(\"revenue_distributions\")\n}\n\nmodel MarketplaceListing {\n  id            String            @id @default(uuid())\n  agentNFTId    String\n  listingId     Int               @unique\n  seller        String\n  shareAmount   Decimal\n  pricePerShare Decimal\n  totalPrice    Decimal\n  status        MarketplaceStatus @default(ACTIVE)\n  expiresAt     DateTime?\n  createdAt     DateTime          @default(now())\n  updatedAt     DateTime          @updatedAt\n\n  agentNFT AgentNFT           @relation(fields: [agentNFTId], references: [id], onDelete: Cascade)\n  offers   MarketplaceOffer[]\n\n  @@map(\"marketplace_listings\")\n}\n\nmodel MarketplaceOffer {\n  id          String      @id @default(uuid())\n  listingId   String\n  buyer       String\n  shareAmount Decimal\n  offerPrice  Decimal\n  status      OfferStatus @default(PENDING)\n  expiresAt   DateTime?\n  createdAt   DateTime    @default(now())\n  updatedAt   DateTime    @updatedAt\n\n  listing MarketplaceListing @relation(fields: [listingId], references: [id], onDelete: Cascade)\n\n  @@map(\"marketplace_offers\")\n}\n\nenum MarketplaceStatus {\n  ACTIVE\n  SOLD\n  CANCELLED\n  EXPIRED\n}\n\nenum OfferStatus {\n  PENDING\n  ACCEPTED\n  REJECTED\n  CANCELLED\n  EXPIRED\n}\n\n// =============================================================================\n// WALLET AND TRANSACTION MODELS\n// =============================================================================\n\nmodel Wallet {\n  id           String     @id @default(uuid())\n  address      String     @unique\n  agentId      String?    @unique\n  type         WalletType @default(SMART_ACCOUNT)\n  balance      Decimal    @default(0)\n  nonce        Int        @default(0)\n  isActive     Boolean    @default(true)\n  lastActivity DateTime?\n  createdAt    DateTime   @default(now())\n  updatedAt    DateTime   @updatedAt\n\n  agent        Agent?        @relation(fields: [agentId], references: [id])\n  transactions Transaction[]\n\n  @@map(\"wallets\")\n}\n\nmodel Transaction {\n  id          String            @id @default(uuid())\n  hash        String            @unique\n  walletId    String\n  fromAddress String\n  toAddress   String\n  value       Decimal\n  gasPrice    Decimal\n  gasUsed     Int\n  gasLimit    Int\n  status      TransactionStatus @default(PENDING)\n  blockNumber Int?\n  blockHash   String?\n  type        TransactionType   @default(TRANSFER)\n  data        Json?\n  createdAt   DateTime          @default(now())\n  confirmedAt DateTime?\n\n  wallet Wallet @relation(fields: [walletId], references: [id], onDelete: Cascade)\n\n  @@index([walletId])\n  @@index([hash])\n  @@index([status])\n  @@index([createdAt])\n  @@map(\"transactions\")\n}\n\nenum WalletType {\n  SMART_ACCOUNT\n  EOA\n  MULTI_SIG\n}\n\nenum TransactionStatus {\n  PENDING\n  CONFIRMED\n  FAILED\n  CANCELLED\n}\n\nenum TransactionType {\n  TRANSFER\n  CONTRACT_CALL\n  CONTRACT_DEPLOYMENT\n  NFT_MINT\n  NFT_TRANSFER\n}\n\n// =============================================================================\n// LLM CONFIGURATION\n// =============================================================================\n\nmodel LLMConfig {\n  id          String    @id @default(uuid())\n  name        String\n  provider    String\n  modelName   String\n  apiKey      String // Should be encrypted in production\n  apiEndpoint String?\n  isCustom    Boolean   @default(false)\n  enabled     Boolean   @default(true)\n  priority    Int       @default(10)\n  retryConfig Json?\n  createdAt   DateTime  @default(now())\n  updatedAt   DateTime  @updatedAt\n  deletedAt   DateTime?\n\n  @@map(\"llm_configs\")\n}\n\n// =============================================================================\n// MULTI-TENANT SYNCHRONIZATION SYSTEM\n// =============================================================================\n\nmodel SyncState {\n  id           String   @id @default(uuid())\n  resourceType String // 'agent', 'template', 'config', etc.\n  resourceId   String\n  tenantId     String?\n  version      Int      @default(1)\n  checksum     String\n  lastSync     DateTime @default(now())\n  syncedBy     String // instance ID\n  metadata     Json?\n\n  @@index([resourceType])\n  @@index([tenantId])\n  @@index([lastSync])\n  @@index([resourceType, resourceId, tenantId])\n  @@map(\"sync_states\")\n}\n\nmodel SyncConflict {\n  id            String    @id @default(uuid())\n  resourceType  String\n  resourceId    String\n  tenantId      String?\n  conflictType  String // 'version', 'checksum', 'concurrent'\n  localVersion  Json\n  remoteVersion Json\n  resolvedAt    DateTime?\n  resolvedBy    String?\n  resolution    Json?\n  createdAt     DateTime  @default(now())\n\n  @@index([resourceType])\n  @@index([tenantId])\n  @@index([createdAt])\n  @@index([resolvedAt])\n  @@map(\"sync_conflicts\")\n}\n\n// =============================================================================\n// AGENT REGISTRY SYSTEM\n// =============================================================================\n\nmodel AgentRegistration {\n  id                   String             @id @default(uuid())\n  agentId              String             @unique\n  authToken            String             @unique\n  registrationData     Json // Original registration payload\n  verificationStatus   VerificationStatus @default(PENDING)\n  onboardingStatus     OnboardingStatus   @default(INITIALIZED)\n  onboardingStep       String? // Current step in onboarding\n  onboardingProgress   Int                @default(0) // 0-100\n  orientationCompleted Boolean            @default(false)\n  firstConnectedAt     DateTime           @default(now())\n  lastHeartbeat        DateTime           @default(now())\n  heartbeatInterval    Int                @default(60000) // milliseconds\n  isOnline             Boolean            @default(false)\n  metadata             Json?\n  createdAt            DateTime           @default(now())\n  updatedAt            DateTime           @updatedAt\n\n  // Relationships\n  agent            Agent                     @relation(fields: [agentId], references: [id], onDelete: Cascade)\n  capabilities     AgentCapabilityRegistry[]\n  metrics          AgentMetrics[]\n  onboardingEvents AgentOnboardingEvent[]\n\n  @@index([authToken])\n  @@index([verificationStatus])\n  @@index([onboardingStatus])\n  @@index([isOnline])\n  @@index([lastHeartbeat])\n  @@map(\"agent_registrations\")\n}\n\nmodel AgentCapabilityRegistry {\n  id                 String             @id @default(uuid())\n  registrationId     String\n  capabilityName     String\n  capabilityType     String // 'core', 'extended', 'custom'\n  version            String?\n  description        String?\n  parameters         Json? // Capability configuration\n  verificationStatus VerificationStatus @default(PENDING)\n  verifiedAt         DateTime?\n  testResults        Json? // Results from capability testing\n  isActive           Boolean            @default(true)\n  createdAt          DateTime           @default(now())\n  updatedAt          DateTime           @updatedAt\n\n  // Relationships\n  registration AgentRegistration @relation(fields: [registrationId], references: [id], onDelete: Cascade)\n\n  @@index([registrationId])\n  @@index([capabilityName])\n  @@index([verificationStatus])\n  @@map(\"agent_capability_registry\")\n}\n\nmodel AgentMetrics {\n  id             String   @id @default(uuid())\n  registrationId String\n  metricType     String // 'task_completion', 'response_time', 'error_rate', etc.\n  value          Float\n  unit           String?\n  timestamp      DateTime @default(now())\n  tags           Json? // Additional metadata for metrics\n\n  // Relationships\n  registration AgentRegistration @relation(fields: [registrationId], references: [id], onDelete: Cascade)\n\n  @@index([registrationId])\n  @@index([metricType])\n  @@index([timestamp])\n  @@map(\"agent_metrics\")\n}\n\nmodel AgentOnboardingEvent {\n  id             String              @id @default(uuid())\n  registrationId String\n  eventType      OnboardingEventType\n  eventData      Json?\n  message        String?\n  timestamp      DateTime            @default(now())\n\n  // Relationships\n  registration AgentRegistration @relation(fields: [registrationId], references: [id], onDelete: Cascade)\n\n  @@index([registrationId])\n  @@index([eventType])\n  @@index([timestamp])\n  @@map(\"agent_onboarding_events\")\n}\n\nmodel AgentDirectoryEntry {\n  id             String   @id @default(uuid())\n  agentId        String   @unique\n  displayName    String\n  description    String?\n  category       String? // 'development', 'analytics', 'automation', etc.\n  tags           String[] @default([])\n  isPublic       Boolean  @default(false)\n  isVerified     Boolean  @default(false)\n  rating         Float?   @default(0)\n  usageCount     Int      @default(0)\n  lastActiveAt   DateTime @default(now())\n  featured       Boolean  @default(false)\n  searchableData String?  @db.Text // Denormalized search data\n  metadata       Json?\n  createdAt      DateTime @default(now())\n  updatedAt      DateTime @updatedAt\n\n  @@index([category])\n  @@index([isPublic])\n  @@index([isVerified])\n  @@index([featured])\n  @@index([rating])\n  @@index([lastActiveAt])\n  @@map(\"agent_directory_entries\")\n}\n\nenum VerificationStatus {\n  PENDING\n  IN_PROGRESS\n  VERIFIED\n  FAILED\n  REJECTED\n}\n\nenum OnboardingStatus {\n  INITIALIZED\n  WELCOME_SENT\n  CAPABILITIES_TESTED\n  ORIENTATION_IN_PROGRESS\n  ORIENTATION_COMPLETED\n  INTEGRATION_TESTING\n  READY\n  FAILED\n}\n\nenum OnboardingEventType {\n  REGISTRATION_STARTED\n  WELCOME_MESSAGE_SENT\n  CAPABILITY_DECLARED\n  CAPABILITY_VERIFIED\n  CAPABILITY_FAILED\n  ORIENTATION_STARTED\n  ORIENTATION_STEP_COMPLETED\n  ORIENTATION_COMPLETED\n  INTEGRATION_TEST_STARTED\n  INTEGRATION_TEST_PASSED\n  INTEGRATION_TEST_FAILED\n  TASK_ASSIGNED\n  TASK_COMPLETED\n  ERROR_OCCURRED\n  STATUS_CHANGED\n}\n\n// =============================================================================\n// RESOURCE REGISTRY SYSTEM\n// =============================================================================\n\nmodel Resource {\n  id          String             @id @default(uuid())\n  name        String\n  description String?            @db.Text\n  category    ResourceCategory\n  type        ResourceType\n  content     Json\n  tags        String[]           @default([])\n  version     String\n  source      String\n  visibility  ResourceVisibility @default(PUBLIC)\n\n  // Metadata\n  author     String?\n  authorId   String?\n  license    String?\n  homepage   String?\n  repository String?\n\n  // Search and discovery\n  searchableText String?  @db.Text\n  keywords       String[] @default([])\n\n  // Usage tracking\n  usageCount    Int @default(0)\n  downloadCount Int @default(0)\n  favoriteCount Int @default(0)\n\n  // Status and validation\n  status     ResourceStatus @default(ACTIVE)\n  isVerified Boolean        @default(false)\n  isFeatured Boolean        @default(false)\n\n  // Relationships\n  dependencies     String[] @default([])\n  relatedResources String[] @default([])\n\n  // Timestamps\n  createdAt    DateTime  @default(now())\n  updatedAt    DateTime  @updatedAt\n  publishedAt  DateTime?\n  deprecatedAt DateTime?\n  deletedAt    DateTime?\n\n  // Relationships\n  versions   ResourceVersion[]\n  metadata   ResourceMetadata?\n  accessLogs ResourceAccessLog[]\n\n  @@index([category])\n  @@index([type])\n  @@index([visibility])\n  @@index([status])\n  @@index([authorId])\n  @@index([createdAt])\n  @@index([tags])\n  @@index([keywords])\n  @@map(\"resources\")\n}\n\nmodel ResourceVersion {\n  id         String  @id @default(uuid())\n  resourceId String\n  version    String\n  changelog  String? @db.Text\n  content    Json\n  isLatest   Boolean @default(false)\n  isDraft    Boolean @default(false)\n\n  createdAt DateTime @default(now())\n  createdBy String?\n\n  // Relationships\n  resource Resource @relation(fields: [resourceId], references: [id], onDelete: Cascade)\n\n  @@unique([resourceId, version])\n  @@index([resourceId])\n  @@index([version])\n  @@index([isLatest])\n  @@map(\"resource_versions\")\n}\n\nmodel ResourceMetadata {\n  id         String @id @default(uuid())\n  resourceId String @unique\n\n  // Extended metadata\n  metadata Json @default(\"{}\")\n\n  // Performance metrics\n  performanceMetrics Json?\n\n  // Quality scores\n  qualityScore    Float?\n  complexityScore Float?\n\n  // Additional fields\n  estimatedExecutionTime Int?\n  requiredDependencies   String[] @default([])\n  optionalDependencies   String[] @default([])\n\n  // Environment requirements\n  minimumNodeVersion String?\n  platforms          String[] @default([])\n\n  // Configuration\n  configSchema Json?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relationships\n  resource Resource @relation(fields: [resourceId], references: [id], onDelete: Cascade)\n\n  @@map(\"resource_metadata\")\n}\n\nmodel ResourceAccessLog {\n  id           String         @id @default(uuid())\n  resourceId   String\n  accessorId   String?\n  accessorType String\n  action       ResourceAction\n  ipAddress    String?\n  userAgent    String?\n  metadata     Json?\n  timestamp    DateTime       @default(now())\n\n  // Relationships\n  resource Resource @relation(fields: [resourceId], references: [id], onDelete: Cascade)\n\n  @@index([resourceId])\n  @@index([accessorId])\n  @@index([action])\n  @@index([timestamp])\n  @@map(\"resource_access_logs\")\n}\n\nenum ResourceCategory {\n  CLAUDE_SKILL\n  N8N_WORKFLOW\n  AGENT_TEMPLATE\n  CODE_SNIPPET\n  DOCUMENTATION\n  TOOL\n  INTEGRATION\n  WORKFLOW_TEMPLATE\n  API_ENDPOINT\n  DATABASE_SCHEMA\n  UI_COMPONENT\n  CONFIGURATION\n  SCRIPT\n  PROMPT_TEMPLATE\n  DATA_SOURCE\n}\n\nenum ResourceType {\n  JAVASCRIPT\n  TYPESCRIPT\n  PYTHON\n  SHELL\n  SQL\n  JSON\n  YAML\n  TOML\n  ENV\n  MARKDOWN\n  HTML\n  PDF\n  N8N_JSON\n  ZAPIER_JSON\n  MAKE_JSON\n  TEMPLATE\n  SNIPPET\n  OPENAPI\n  GRAPHQL\n  REST\n  BINARY\n  ARCHIVE\n  CUSTOM\n}\n\nenum ResourceVisibility {\n  PUBLIC\n  AGENTS_ONLY\n  PRIVATE\n  RESTRICTED\n  INTERNAL\n}\n\nenum ResourceStatus {\n  DRAFT\n  ACTIVE\n  DEPRECATED\n  ARCHIVED\n  DELETED\n  PENDING_REVIEW\n}\n\nenum ResourceAction {\n  VIEW\n  DOWNLOAD\n  EXECUTE\n  UPDATE\n  DELETE\n  FORK\n  FAVORITE\n  SHARE\n}\n"
}

